import { Input, Message } from "./types";

type Output = {
  data: boolean; // Qualification status
};

// Input topics
export const inputs = [
  "/autodrive/f1tenth_1/lap_count",
  "/autodrive/f1tenth_1/collision_count",
];

// Output topic
export const output = "/autodrive/f1tenth_1/qualification_status";

// Variables
let lapCount = 0;
let collisionCount = 0;
let collisionsDuringWarmup = 0; // Collisions during warmup lap (0)
let collisionsDuringRace = 0; // Collisions during race laps (1-10)

// Script
export default function script(
  event:
    | Input<"/autodrive/f1tenth_1/lap_count">
    | Input<"/autodrive/f1tenth_1/collision_count">,
): Output {
  if (event.topic === "/autodrive/f1tenth_1/lap_count") {
    // Read event.message fields expected for /autodrive/f1tenth_1/lap_count messages
    lapCount = event.message.data;
  } else {
    // Read event.message fields expected for /autodrive/f1tenth_1/collision_count messages
    collisionCount = event.message.data;
  }

  // Debugging
  // log(event.message.data);

  // Define the qualification status logic
  let qualificationStatus = true;

  if (lapCount < 1) {
    // Ignore collisions during warmup lap (0)
    collisionsDuringRace = 0;
    collisionsDuringWarmup = collisionCount;
    qualificationStatus = true;
  } else if (lapCount >= 1 && lapCount <= 10) {
    // Calculate collisions during race laps (1 to 10)
    collisionsDuringRace = collisionCount - collisionsDuringWarmup;
    qualificationStatus = collisionsDuringRace <= 10;
  }

  // Debugging
  // log(collisionsDuringWarmup);
  // log(collisionsDuringRace);
  // log(qualificationStatus);

  // Return the qualification status as the output
  return {
    data: qualificationStatus,
  };
}

