import { Input, Message } from "./types";

type Output = {
  data: number; // Adjusted race time (seconds)
};

// Input topics
export const inputs = [
  "/autodrive/f1tenth_1/lap_count",
  "/autodrive/f1tenth_1/collision_count",
  "/autodrive/f1tenth_1/last_lap_time",
];

// Output topic
export const output = "/autodrive/f1tenth_1/adjusted_race_time";

// Variables
let lapCount = 0; // Current lap count
let collisionCount = 0; // Current collision count
let collisionsDuringWarmup = 0; // Collisions during warmup lap (0)
let collisionsDuringRace = 0; // Collisions during race laps (1-10)
let lastLapCount = -1; // Track the previous lap count
let lastLapTime = 0; // Track the previous lap time
let raceTime = 0; // Time elapsed during race laps (1-10)
let adjustedRaceTime = 0; // Race time with penalties

// Script
export default function script(
  event:
    | Input<"/autodrive/f1tenth_1/lap_count">
    | Input<"/autodrive/f1tenth_1/collision_count">
    | Input<"/autodrive/f1tenth_1/last_lap_time">,
): Output {
  if (event.topic === "/autodrive/f1tenth_1/lap_count") {
    // Read event.message fields expected for /autodrive/f1tenth_1/lap_count messages
    lapCount = event.message.data;
  } else if (event.topic === "/autodrive/f1tenth_1/collision_count") {
    // Read event.message fields expected for /autodrive/f1tenth_1/collision_count messages
    collisionCount = event.message.data;
  } else {
    // Read event.message fields expected for /autodrive/f1tenth_1/last_lap_time messages
    lastLapTime = event.message.data;
  }

  // Debugging
  // log(event.message.data);

  // Calculate collisions only for race laps
  if (lapCount < 1) {
    // Ignore collisions during warmup lap (0)
    collisionsDuringRace = 0;
    collisionsDuringWarmup = collisionCount;
  } else if (lapCount >= 1 && lapCount <= 10) {
    // Calculate collisions during race laps (1 to 10)
    collisionsDuringRace = collisionCount - collisionsDuringWarmup;
  }

  // Check time only for race laps
  if (lapCount >= 3 && lapCount <= 12) {
    // Only add time once per lap increment
    if (lapCount > lastLapCount) {
      raceTime += lastLapTime;
      lastLapCount = lapCount;
    }
  }

  // Calculate adjusted race time
  if (lapCount > 11) {
    adjustedRaceTime = raceTime + 10 * collisionsDuringRace;
  }

  // Debugging
  // log(collisionsDuringWarmup);
  // log(collisionsDuringRace);
  // log(lastLapTime);
  // log(raceTime);
  // log(adjustedRaceTime);

  // Return the qualification status as the output
  return {
    data: adjustedRaceTime,
  };
}
